(function (global) {
  "use strict";

  const VERSION = 10;
  const SIZE = VERSION * 4 + 17;
  const DATA_CODEWORDS = 274;
  const EC_CODEWORDS = 18;
  const BLOCK_LENGTHS = [68, 68, 69, 69];
  const ALIGNMENT = [6, 28, 50];
  const G15 = 0x537;
  const G18 = 0x1f25;
  const G15_MASK = 0x5412;
  const EXP = new Array(512);
  const LOG = new Array(256);

  let x = 1;
  for (let i = 0; i < 255; i += 1) {
    EXP[i] = x;
    LOG[x] = i;
    x <<= 1;
    if (x & 0x100) x ^= 0x11d;
  }
  for (let i = 255; i < 512; i += 1) EXP[i] = EXP[i - 255];

  function gfMul(a, b) {
    if (!a || !b) return 0;
    return EXP[LOG[a] + LOG[b]];
  }

  function polyMultiply(a, b) {
    const out = new Array(a.length + b.length - 1).fill(0);
    for (let i = 0; i < a.length; i += 1) {
      for (let j = 0; j < b.length; j += 1) {
        out[i + j] ^= gfMul(a[i], b[j]);
      }
    }
    return out;
  }

  function generatorPoly(degree) {
    let poly = [1];
    for (let i = 0; i < degree; i += 1) {
      poly = polyMultiply(poly, [1, EXP[i]]);
    }
    return poly;
  }

  const EC_GENERATOR = generatorPoly(EC_CODEWORDS);

  function rsEncode(data) {
    const result = new Array(EC_CODEWORDS).fill(0);
    data.forEach((byte) => {
      const factor = byte ^ result[0];
      result.shift();
      result.push(0);
      if (!factor) return;
      for (let i = 0; i < EC_CODEWORDS; i += 1) {
        result[i] ^= gfMul(EC_GENERATOR[i + 1], factor);
      }
    });
    return result;
  }

  function getBchDigit(data) {
    let digit = 0;
    while (data !== 0) {
      digit += 1;
      data >>>= 1;
    }
    return digit;
  }

  function getBchTypeInfo(data) {
    let d = data << 10;
    while (getBchDigit(d) - getBchDigit(G15) >= 0) {
      d ^= G15 << (getBchDigit(d) - getBchDigit(G15));
    }
    return ((data << 10) | d) ^ G15_MASK;
  }

  function getBchTypeNumber(data) {
    let d = data << 12;
    while (getBchDigit(d) - getBchDigit(G18) >= 0) {
      d ^= G18 << (getBchDigit(d) - getBchDigit(G18));
    }
    return (data << 12) | d;
  }

  function utf8Bytes(text) {
    if (global.TextEncoder) return Array.from(new TextEncoder().encode(String(text)));
    return Array.from(unescape(encodeURIComponent(String(text)))).map((ch) => ch.charCodeAt(0));
  }

  function BitBuffer() {
    this.bits = [];
  }

  BitBuffer.prototype.put = function put(num, length) {
    for (let i = length - 1; i >= 0; i -= 1) {
      this.bits.push((num >>> i) & 1);
    }
  };

  BitBuffer.prototype.toBytes = function toBytes() {
    const bytes = [];
    for (let i = 0; i < this.bits.length; i += 8) {
      let value = 0;
      for (let j = 0; j < 8; j += 1) value = (value << 1) | (this.bits[i + j] || 0);
      bytes.push(value);
    }
    return bytes;
  };

  function createData(text) {
    const bytes = utf8Bytes(text);
    if (bytes.length > DATA_CODEWORDS - 3) {
      throw new Error("QR payload is too long.");
    }

    const buffer = new BitBuffer();
    buffer.put(4, 4);
    buffer.put(bytes.length, 16);
    bytes.forEach((byte) => buffer.put(byte, 8));

    const maxBits = DATA_CODEWORDS * 8;
    buffer.put(0, Math.min(4, maxBits - buffer.bits.length));
    while (buffer.bits.length % 8 !== 0) buffer.put(0, 1);

    const data = buffer.toBytes();
    let pad = 0xec;
    while (data.length < DATA_CODEWORDS) {
      data.push(pad);
      pad = pad === 0xec ? 0x11 : 0xec;
    }

    const blocks = [];
    let offset = 0;
    BLOCK_LENGTHS.forEach((length) => {
      const block = data.slice(offset, offset + length);
      offset += length;
      blocks.push({
        data: block,
        ec: rsEncode(block)
      });
    });

    const out = [];
    const maxDataLength = Math.max.apply(null, BLOCK_LENGTHS);
    for (let i = 0; i < maxDataLength; i += 1) {
      blocks.forEach((block) => {
        if (i < block.data.length) out.push(block.data[i]);
      });
    }
    for (let i = 0; i < EC_CODEWORDS; i += 1) {
      blocks.forEach((block) => out.push(block.ec[i]));
    }
    return out;
  }

  function createMatrix(text) {
    const modules = Array.from({ length: SIZE }, () => new Array(SIZE).fill(false));
    const reserved = Array.from({ length: SIZE }, () => new Array(SIZE).fill(false));

    function set(row, col, value, reserve) {
      if (row < 0 || row >= SIZE || col < 0 || col >= SIZE) return;
      modules[row][col] = !!value;
      if (reserve !== false) reserved[row][col] = true;
    }

    function setupFinder(row, col) {
      for (let r = -1; r <= 7; r += 1) {
        for (let c = -1; c <= 7; c += 1) {
          const rr = row + r;
          const cc = col + c;
          if (rr < 0 || rr >= SIZE || cc < 0 || cc >= SIZE) continue;
          const dark = r >= 0 && r <= 6 && c >= 0 && c <= 6 &&
            (r === 0 || r === 6 || c === 0 || c === 6 || (r >= 2 && r <= 4 && c >= 2 && c <= 4));
          set(rr, cc, dark);
        }
      }
    }

    function setupAlignment(row, col) {
      for (let r = -2; r <= 2; r += 1) {
        for (let c = -2; c <= 2; c += 1) {
          set(row + r, col + c, Math.max(Math.abs(r), Math.abs(c)) !== 1);
        }
      }
    }

    setupFinder(0, 0);
    setupFinder(SIZE - 7, 0);
    setupFinder(0, SIZE - 7);

    ALIGNMENT.forEach((row) => {
      ALIGNMENT.forEach((col) => {
        if ((row === 6 && col === 6) || (row === 6 && col === SIZE - 7) || (row === SIZE - 7 && col === 6)) return;
        setupAlignment(row, col);
      });
    });

    for (let i = 8; i < SIZE - 8; i += 1) {
      const dark = i % 2 === 0;
      set(6, i, dark);
      set(i, 6, dark);
    }

    const typeInfo = getBchTypeInfo((1 << 3) | 0);
    for (let i = 0; i < 15; i += 1) {
      const dark = ((typeInfo >> i) & 1) === 1;
      if (i < 6) set(i, 8, dark);
      else if (i < 8) set(i + 1, 8, dark);
      else set(SIZE - 15 + i, 8, dark);

      if (i < 8) set(8, SIZE - i - 1, dark);
      else if (i < 9) set(8, 15 - i, dark);
      else set(8, 15 - i - 1, dark);
    }
    set(SIZE - 8, 8, true);

    const versionInfo = getBchTypeNumber(VERSION);
    for (let i = 0; i < 18; i += 1) {
      const dark = ((versionInfo >> i) & 1) === 1;
      set(Math.floor(i / 3), (i % 3) + SIZE - 11, dark);
      set((i % 3) + SIZE - 11, Math.floor(i / 3), dark);
    }

    const data = createData(text);
    const bits = [];
    data.forEach((byte) => {
      for (let i = 7; i >= 0; i -= 1) bits.push((byte >>> i) & 1);
    });

    let bitIndex = 0;
    let direction = -1;
    let row = SIZE - 1;
    for (let col = SIZE - 1; col > 0; col -= 2) {
      if (col === 6) col -= 1;
      while (true) {
        for (let c = 0; c < 2; c += 1) {
          const cc = col - c;
          if (!reserved[row][cc]) {
            const bit = bitIndex < bits.length ? bits[bitIndex] === 1 : false;
            const masked = bit !== ((row + cc) % 2 === 0);
            modules[row][cc] = masked;
            bitIndex += 1;
          }
        }
        row += direction;
        if (row < 0 || row >= SIZE) {
          row -= direction;
          direction = -direction;
          break;
        }
      }
    }

    return modules;
  }

  function toCanvas(canvas, text, options, callback) {
    const done = typeof options === "function" ? options : callback;
    const opts = typeof options === "object" && options ? options : {};
    try {
      const target = typeof canvas === "string" ? document.querySelector(canvas) : canvas;
      if (!target || !target.getContext) throw new Error("Canvas element is required.");
      const modules = createMatrix(text);
      const margin = Number.isFinite(Number(opts.margin)) ? Number(opts.margin) : 4;
      const width = Math.max(120, Number(opts.width || 256));
      const cell = Math.max(1, Math.floor(width / (SIZE + margin * 2)));
      const actual = cell * (SIZE + margin * 2);
      const dark = opts.color?.dark || "#111111";
      const light = opts.color?.light || "#ffffff";
      target.width = actual;
      target.height = actual;
      const ctx = target.getContext("2d");
      ctx.fillStyle = light;
      ctx.fillRect(0, 0, actual, actual);
      ctx.fillStyle = dark;
      for (let r = 0; r < SIZE; r += 1) {
        for (let c = 0; c < SIZE; c += 1) {
          if (modules[r][c]) ctx.fillRect((c + margin) * cell, (r + margin) * cell, cell, cell);
        }
      }
      if (done) done(null);
      return target;
    } catch (err) {
      if (done) {
        done(err);
        return null;
      }
      throw err;
    }
  }

  global.QRCode = global.QRCode || {};
  global.QRCode.toCanvas = global.QRCode.toCanvas || toCanvas;
})(window);
